    # Component 5: Dynamic weight for idle taxis (prioritize)
    weight_multiplier = 2  # Higher multiplier prioritizes idle taxis more
    cost5 = gb.quicksum(
        weight_multiplier * self.y[v, p]  # Assign higher weight to idle taxis
        for v in [v for v in self.taxi.keys() if self.taxi[v].arrival_time == 0]
        for p in self.passenger.keys()
    )

    # Combine components with weights
    costs = [cost1, cost2, cost3, cost4, cost5]
    weights = [150, 50, 50, 10000, 200]

    # Build objective expression
    objective = sum(w * c for w, c in zip(weights, costs))
    self.model.setObjective(objective, gb.GRB.MINIMIZE)"
}
